import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Button,
  Heading,
  Text,
  Card,
  Badge,
  Divider,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Element[];
}

const CATEGORY_MAP: Record<string, { bg: string; text: string; label: string; badgeVariant: 'primary' | 'error' | 'warning' | 'info' | 'success' | 'secondary' | 'default' }> = {
  'noble-gas': {
    bg: 'var(--ggui-color-primary-100)',
    text: 'var(--ggui-color-primary-800)',
    label: 'Noble Gas',
    badgeVariant: 'primary'
  },
  'alkali-metal': {
    bg: 'var(--ggui-color-error-100)',
    text: 'var(--ggui-color-error-800)',
    label: 'Alkali Metal',
    badgeVariant: 'error'
  },
  'alkaline-earth': {
    bg: 'var(--ggui-color-warning-100)',
    text: 'var(--ggui-color-warning-800)',
    label: 'Alkaline Earth Metal',
    badgeVariant: 'warning'
  },
  'metalloid': {
    bg: 'var(--ggui-color-info-100)',
    text: 'var(--ggui-color-info-800)',
    label: 'Metalloid',
    badgeVariant: 'info'
  },
  'nonmetal': {
    bg: 'var(--ggui-color-success-100)',
    text: 'var(--ggui-color-success-800)',
    label: 'Nonmetal',
    badgeVariant: 'success'
  },
  'transition-metal': {
    bg: 'var(--ggui-color-neutral-100)',
    text: 'var(--ggui-color-neutral-700)',
    label: 'Transition Metal',
    badgeVariant: 'secondary'
  },
  'lanthanide': {
    bg: 'var(--ggui-color-primary-50)',
    text: 'var(--ggui-color-primary-700)',
    label: 'Lanthanide',
    badgeVariant: 'primary'
  },
  'actinide': {
    bg: 'var(--ggui-color-primary-50)',
    text: 'var(--ggui-color-primary-700)',
    label: 'Actinide',
    badgeVariant: 'primary'
  },
  'post-transition-metal': {
    bg: 'var(--ggui-color-neutral-100)',
    text: 'var(--ggui-color-neutral-700)',
    label: 'Post-transition Metal',
    badgeVariant: 'secondary'
  },
  'default': {
    bg: 'var(--ggui-color-surfaceVariant)',
    text: 'var(--ggui-color-onSurface)',
    label: 'Other',
    badgeVariant: 'default'
  }
};

const getCategoryKey = (category?: string) => {
  if (!category) return 'default';
  const c = category.toLowerCase();
  if (c.includes('noble gas')) return 'noble-gas';
  if (c.includes('alkali metal')) return 'alkali-metal';
  if (c.includes('alkaline earth')) return 'alkaline-earth';
  if (c.includes('metalloid')) return 'metalloid';
  if (c.includes('nonmetal')) return 'nonmetal';
  if (c.includes('transition metal')) return 'transition-metal';
  if (c.includes('lanthanide')) return 'lanthanide';
  if (c.includes('actinide')) return 'actinide';
  if (c.includes('post-transition')) return 'post-transition-metal';
  return 'default';
};

export default function PeriodicTable({ elements }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return elements;
    return elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(query) ||
        e.symbol?.toLowerCase().includes(query)
    );
  }, [elements, searchQuery]);

  const uniqueCategories = useMemo(() => {
    const keys = Array.from(new Set(elements.map((e) => getCategoryKey(e.category))));
    return keys.map((key) => ({
      key,
      ...CATEGORY_MAP[key]
    }));
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header Section */}
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={1}>Periodic Table</Heading>
          <Box style={{ width: 'var(--ggui-spacing-80)' }}>
            <SearchField
              value={searchQuery}
              onChange={setSearchQuery}
              placeholder="Search by name or symbol..."
              size="md"
            />
          </Box>
        </Stack>

        {/* Periodic Table Grid */}
        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4)' }}>
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(var(--ggui-spacing-10), 1fr))',
              gap: 'var(--ggui-spacing-1)',
              minWidth: 'var(--ggui-spacing-200)'
            }}
          >
            {elements.map((element) => {
              const isFiltered = !filteredElements.find((fe) => fe.atomicNumber === element.atomicNumber);
              const isSelected = selectedElement?.atomicNumber === element.atomicNumber;
              const catKey = getCategoryKey(element.category);
              const styles = CATEGORY_MAP[catKey] || CATEGORY_MAP.default;

              return (
                <Box
                  key={element.atomicNumber}
                  style={{
                    gridRow: element.row,
                    gridColumn: element.col,
                    aspectRatio: '1/1',
                    opacity: isFiltered ? 0.2 : 1,
                    transition: 'opacity 200ms ease'
                  }}
                >
                  <Button
                    variant="ghost"
                    onPress={() => setSelectedElement(element)}
                    aria-label={`${element.atomicNumber} ${element.name} (${element.symbol})`}
                    style={{
                      width: '100%',
                      height: '100%',
                      padding: 'var(--ggui-spacing-1)',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      justifyContent: 'center',
                      backgroundColor: styles.bg,
                      color: styles.text,
                      border: '1px solid var(--ggui-color-outlineVariant)',
                      borderRadius: 'var(--ggui-shape-radius-md)',
                      outline: isSelected ? '2px solid var(--ggui-color-primary-600)' : 'none',
                      outlineOffset: isSelected ? '1px' : '0',
                      position: 'relative',
                      overflow: 'hidden'
                    }}
                  >
                    <Text
                      variant="caption"
                      style={{
                        position: 'absolute',
                        top: 'var(--ggui-spacing-1)',
                        left: 'var(--ggui-spacing-1)',
                        fontSize: 'var(--ggui-font-size-xs)',
                        color: styles.text,
                        fontWeight: 'bold'
                      }}
                    >
                      {element.atomicNumber}
                    </Text>
                    <Text
                      variant="bodyLarge"
                      weight="bold"
                      style={{ fontSize: 'var(--ggui-font-size-lg)', lineHeight: 1, color: styles.text }}
                    >
                      {element.symbol}
                    </Text>
                  </Button>
                </Box>
              );
            })}
          </Box>
        </Box>

        {/* Legend Section */}
        <Stack gap="var(--ggui-spacing-3)">
          <Text variant="label">Element Categories</Text>
          <Stack direction="horizontal" wrap gap="var(--ggui-spacing-4)" align="center">
            {uniqueCategories.map((cat) => (
              <Stack key={cat.key} direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Box
                  style={{
                    width: 'var(--ggui-spacing-4)',
                    height: 'var(--ggui-spacing-4)',
                    backgroundColor: cat.bg,
                    borderRadius: 'var(--ggui-shape-radius-sm)',
                    border: '1px solid var(--ggui-color-outlineVariant)'
                  }}
                />
                <Text variant="bodySmall">{cat.label}</Text>
              </Stack>
            ))}
          </Stack>
        </Stack>

        {/* Detail Panel */}
        {selectedElement && (
          <Box style={{ animation: 'ggui-slideInUp 300ms ease-out' }}>
            <Card padding="var(--ggui-spacing-8)" shadow="md" border radius="xl">
              <Stack direction="horizontal" gap="var(--ggui-spacing-8)" align="center" wrap>
                {/* Large Symbol Display */}
                <Box
                  style={{
                    width: 'var(--ggui-spacing-30)',
                    height: 'var(--ggui-spacing-30)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    backgroundColor: (CATEGORY_MAP[getCategoryKey(selectedElement.category)] || CATEGORY_MAP.default).bg,
                    color: (CATEGORY_MAP[getCategoryKey(selectedElement.category)] || CATEGORY_MAP.default).text,
                    borderRadius: 'var(--ggui-shape-radius-lg)',
                    border: '1px solid var(--ggui-color-outlineVariant)'
                  }}
                >
                  <Text size="4xl" weight="bold">
                    {selectedElement.symbol}
                  </Text>
                </Box>

                <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: 'var(--ggui-spacing-75)' }}>
                  <Stack direction="horizontal" justify="between" align="start">
                    <Stack gap="var(--ggui-spacing-1)">
                      <Heading level={2}>{selectedElement.name}</Heading>
                      <Badge variant={(CATEGORY_MAP[getCategoryKey(selectedElement.category)] || CATEGORY_MAP.default).badgeVariant}>
                        {selectedElement.category || 'Unknown'}
                      </Badge>
                    </Stack>
                    <Stack align="end">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        Atomic Number
                      </Text>
                      <Heading level={3}>{selectedElement.atomicNumber}</Heading>
                    </Stack>
                  </Stack>

                  <Divider margin="var(--ggui-spacing-2)" />

                  <Box
                    style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fit, minmax(var(--ggui-spacing-35), 1fr))',
                      gap: 'var(--ggui-spacing-6)'
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Atomic Weight
                      </Text>
                      <Text variant="bodyLarge" weight="medium">
                        {selectedElement.atomicWeight ?? 'N/A'} u
                      </Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Group / Period
                      </Text>
                      <Text variant="bodyLarge" weight="medium">
                        Group {selectedElement.col}, Period {selectedElement.row}
                      </Text>
                    </Stack>
                  </Box>
                </Stack>
              </Stack>
            </Card>
          </Box>
        )}
      </Stack>
    </Container>
  );
}
